include("DistributionalDynamics.jl")

const func_data, time_params, model_elements            = data_prep(obs_data, method_options);
const (param_vector, param_sizes, priors, meas_ind)     = set_params(model_elements, time_params, method_options)

#TODO: DIME conflicts with the installation of BAT 
# Pkg. rm(DIMES)
# First, we need to define the likelihood (function) for our problem.
SSM(par)     = LogDVal(likeli(model_elements, par, param_sizes, priors, meas_ind, method_options)[1])

# Next, we need to choose a sensible prior for the fit:
BAT_priors = NamedTupleDist(
                        A_B = priors[1],
                        Ω   = [LogNormal(log(.01), 1.2) for i in 1:param_sizes[3][1]],
                        Σ   = [LogNormal(log(.72) / 2, 1) for i in 1:param_sizes[4][1]]
)

# Defines the shape of your parameters 
parshapes = ValueShapes.varshape(BAT_priors) 

# Posterior 
posterior = PosteriorDensity(SSM, BAT_priors)

# Sampling 
samples = bat_sample(posterior, MCMCSampling(mcalg = MetropolisHastings(), nsteps = 10^6, nchains = 4)).result

# To get a better understanding of the data 
SampledDensity(posterior, samples)
println("Mean: $(mean(samples))")

